export enum Category {
  TECHNOLOGY = 'Technology',
  FINANCE = 'Finance',
  HEALTH = 'Health',
  LIFESTYLE = 'Lifestyle',
  BUSINESS = 'Business',
  DESIGN = 'Design',
  EDUCATION = 'Education',
  PRODUCT_REVIEWS = 'Product Reviews'
}

export type PostStatus = 'draft' | 'pending' | 'approved' | 'rejected';

export interface Chapter {
  id: string;
  title: string;
  content: string;
  order: number;
}

export interface AIModerationResult {
  grammarScore: number; // 0-100
  plagiarismRisk: 'low' | 'medium' | 'high';
  isSpam: boolean;
  summary: string;
  flags: string[];
}

export interface Comment {
  id: string;
  author: string;
  date: string;
  content: string;
  avatar: string;
}

export interface Post {
  id: string;
  slug: string;
  title: string;
  excerpt: string;
  content: string; // Full content for legacy/preview
  chapters: Chapter[];
  author: {
    name: string;
    avatar: string;
    bio: string;
  };
  authorId: string;
  category: Category;
  publishDate: string;
  readingTime: string;
  featuredImage: string;
  trending?: boolean;
  comments: Comment[];
  status: PostStatus;
  aiModeration?: AIModerationResult;
  isHighValue?: boolean; // For high RPM targeting
}

export type TransactionType = 'reading_reward' | 'comment_reward' | 'referral_bonus' | 'withdrawal' | 'subscription_fee';
export type TransactionStatus = 'pending' | 'completed' | 'failed';

export interface Transaction {
  id: string;
  amount: number;
  type: TransactionType;
  status: TransactionStatus;
  date: string;
  description: string;
}

export type PlanId = 'free' | 'starter' | 'pro' | 'elite' | 'vip' | 'executive';

export interface SubscriptionPlan {
  id: PlanId;
  name: string;
  price: number;
  readLimit: number;
  commentLimit: number;
  readReward: number;
  commentReward: number;
  features: string[];
}

export interface ReferralEntry {
  id: string;
  userId: string;
  name: string;
  date: string;
  status: 'registered' | 'active';
  rewardEarned: number;
}

export interface UserStats {
  balance: number;
  totalEarnings: number;
  referrals: number;
  referralEarnings: number;
  referralList: ReferralEntry[];
  postsReadToday: number;
  postsReadTarget: number;
  commentsMadeToday: number;
  commentsTarget: number;
  pendingRewards: number;
  lastUpdateDate: string;
  transactions: Transaction[];
}

export type UserStatus = 'active' | 'banned' | 'suspended';

export interface AuthUser {
  id: string;
  name: string;
  email: string;
  role: 'user' | 'admin';
  planId: PlanId;
  status: UserStatus;
  joinedDate: string;
  referredBy?: string;
  referralCode: string;
  avatar: string;
  completedReadingPosts: string[]; // Stores format "postId-chapterId"
  completedCommentPosts: string[];
  lastLimitModalDate: string | null;
}

