  postsReadTarget: 12, // Default free limit
  commentsMadeToday: 0,
  commentsTarget: 5,   // Default free limit
  pendingRewards: 0,
  lastUpdateDate: getTodayDate(),
  transactions: []
};

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<AuthUser | null>(null);
  const [stats, setStats] = useState<UserStats>(INITIAL_STATS);
  const [posts, setPosts] = useState<Post[]>(MOCK_POSTS);
  const [systemPlans, setSystemPlans] = useState<Record<PlanId, SubscriptionPlan>>(INITIAL_PLANS);
  const [allUsers, setAllUsers] = useState<AuthUser[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const savedUser = localStorage.getItem('jw_user');
    const savedStats = localStorage.getItem('jw_stats');
    const savedPosts = localStorage.getItem('jw_posts');
    const savedPlans = localStorage.getItem('jw_system_plans');
    const savedAllUsers = localStorage.getItem('jw_all_users');

    let currentStats = savedStats ? JSON.parse(savedStats) : INITIAL_STATS;
    const currentUser = savedUser ? JSON.parse(savedUser) : null;
    const userPosts = savedPosts ? JSON.parse(savedPosts) : [];
    const currentPlans = savedPlans ? JSON.parse(savedPlans) : INITIAL_PLANS;
    const currentUsers = savedAllUsers ? JSON.parse(savedAllUsers) : [];
    const today = getTodayDate();

    if (currentUser) {
      const plan = currentPlans[currentUser.planId];
      currentStats.postsReadTarget = plan.readLimit;
      currentStats.commentsTarget = plan.commentLimit;
    }

    if (currentStats.lastUpdateDate !== today) {
      currentStats = {
        ...currentStats,
        postsReadToday: 0,
        commentsMadeToday: 0,
        lastUpdateDate: today
      };
    }

    if (savedUser) setUser(currentUser);
    setStats(currentStats);
    setPosts([...MOCK_POSTS, ...userPosts]);
    setSystemPlans(currentPlans);
    setAllUsers(currentUsers.length ? currentUsers : (currentUser ? [currentUser] : []));
    setIsLoading(false);
  }, []);

  useEffect(() => {
    if (user) {
      localStorage.setItem('jw_user', JSON.stringify(user));
      setAllUsers(prev => {
        const index = prev.findIndex(u => u.id === user.id);
        if (index > -1) {
          const newList = [...prev];
          newList[index] = user;
          return newList;
        }
        return [...prev, user];
      });
    }
  }, [user]);

  useEffect(() => {
    localStorage.setItem('jw_stats', JSON.stringify(stats));
  }, [stats]);

  useEffect(() => {
    const userCreatedPosts = posts.filter(p => p.authorId !== 'system');
    localStorage.setItem('jw_posts', JSON.stringify(userCreatedPosts));
  }, [posts]);

  useEffect(() => {
    localStorage.setItem('jw_system_plans', JSON.stringify(systemPlans));
  }, [systemPlans]);

  useEffect(() => {
    localStorage.setItem('jw_all_users', JSON.stringify(allUsers));
  }, [allUsers]);

  const login = async (email: string, password: string) => {
    const isAdmin = email.includes('admin');
    const mockUser: AuthUser = {
      id: isAdmin ? 'admin_1' : 'u1',
      name: isAdmin ? 'Admin Chief' : 'Sarah Chen',
      email,
      role: isAdmin ? 'admin' : 'user',
      planId: 'free',
      status: 'active',
      joinedDate: 'Oct 20, 2024',
      referralCode: isAdmin ? 'CHIEF' : 'SARAH7',
      avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${isAdmin ? 'Admin' : 'Sarah'}`,
      completedReadingPosts: [],
      completedCommentPosts: [],
      lastLimitModalDate: null
    };
    setUser(mockUser);
  };

  const register = async (name: string, email: string, password: string, refCode?: string) => {
    const newUserId = Math.random().toString(36).substr(2, 9);
    const newUser: AuthUser = {
      id: newUserId,
      name,
      email,
      role: 'user',
      planId: 'free',
      status: 'active',
      joinedDate: getTodayDate(),
      referredBy: refCode,
      referralCode: 'REF' + Math.random().toString(36).substring(2, 6).toUpperCase(),
      avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${name}`,
      completedReadingPosts: [],
      completedCommentPosts: [],
      lastLimitModalDate: null
    };
    setUser(newUser);
  };

  const logout = () => {
    setUser(null);
    setStats(INITIAL_STATS);
    setPosts(MOCK_POSTS);
    localStorage.removeItem('jw_user');
    localStorage.removeItem('jw_stats');
    localStorage.removeItem('jw_posts');
  };

  const addReward = (type: 'reading' | 'comment', key: string): boolean => {
    if (!user) return false;
    const plan = systemPlans[user.planId];

    // Safety check for limits
    if (type === 'reading' && stats.postsReadToday >= plan.readLimit) return false;
    if (type === 'comment' && stats.commentsMadeToday >= plan.commentLimit) return false;

    // Safety check for repeated engagement on same item
    if (type === 'reading' && user.completedReadingPosts.includes(key)) return false;
    if (type === 'comment' && user.completedCommentPosts.includes(key)) return false;

    const amount = type === 'reading' ? plan.readReward : plan.commentReward;

    setStats(prev => ({
      ...prev,
      pendingRewards: prev.pendingRewards + amount,
      totalEarnings: prev.totalEarnings + amount,
      postsReadToday: type === 'reading' ? prev.postsReadToday + 1 : prev.postsReadToday,
      commentsMadeToday: type === 'comment' ? prev.commentsMadeToday + 1 : prev.commentsMadeToday,
      transactions: [{ 
        id: `tx_${Date.now()}`, 
        amount, 
        type: type === 'reading' ? 'reading_reward' : 'comment_reward', 
        status: 'pending', 
        date: getTodayDate(), 
        description: `${type === 'reading' ? 'Article Consumption' : 'Community Discussion'} Reward` 
      }, ...prev.transactions]
    }));

    setUser(prev => {
      if (!prev) return null;
      return {
        ...prev,
        completedReadingPosts: type === 'reading' ? [...prev.completedReadingPosts, key] : prev.completedReadingPosts,
        completedCommentPosts: type === 'comment' ? [...prev.completedCommentPosts, key] : prev.completedCommentPosts
      };
    });
    return true;
  };

  const splitIntoChapters = (content: string): Chapter[] => {
    const sections = content.split('<h2>');
    if (sections.length > 1) {
      return sections.map((s, i) => ({
        id: `ch-${i}`,
        title: i === 0 ? "Introduction" : s.substring(0, 30).split('</h2>')[0],
        content: i === 0 ? s : '<h2>' + s,
        order: i + 1
      }));
    }
    const words = content.split(' ');
    const chapters: Chapter[] = [];
    const chunkSize = 400;
    for (let i = 0; i < words.length; i += chunkSize) {
      chapters.push({
        id: `ch-${i / chunkSize}`,
        title: `Segment ${(i / chunkSize) + 1}`,
        content: words.slice(i, i + chunkSize).join(' '),
        order: (i / chunkSize) + 1
      });
    }
    return chapters;
  };

  const savePost = async (postData: Partial<Post>) => {
    if (!user) return;
    let modResult = null;
    if (postData.status === 'pending') {
      modResult = await moderateContent(postData.title || "", postData.content || "");
    }

    const newPost: Post = {
      id: postData.id || Math.random().toString(36).substr(2, 9),
      authorId: user.id,
      author: postData.author || { name: user.name, avatar: user.avatar, bio: 'JobbaWorks Creator' },
      title: postData.title || 'Untitled',
      slug: postData.slug || postData.title?.toLowerCase().replace(/\s+/g, '-') || 'untitled',
      excerpt: postData.excerpt || '',
      content: postData.content || '',
      chapters: postData.chapters || (postData.content ? splitIntoChapters(postData.content) : []),
      category: postData.category || Category.LIFESTYLE,
      featuredImage: postData.featuredImage || 'https://picsum.photos/1200/600',
      publishDate: getTodayDate(),
      readingTime: postData.readingTime || '5 min read',
      comments: postData.comments || [],
      status: postData.status || 'draft',
      aiModeration: modResult
    };

    setPosts(prev => {
      const exists = prev.find(p => p.id === newPost.id);
      if (exists) return prev.map(p => p.id === newPost.id ? newPost : p);
      return [...prev, newPost];
    });
  };

  const updatePostStatus = (postId: string, status: PostStatus) => {
    setPosts(prev => prev.map(p => p.id === postId ? { ...p, status } : p));
  };

  const manageUserStatus = (userId: string, status: UserStatus) => {
    setAllUsers(prev => prev.map(u => u.id === userId ? { ...u, status } : u));
  };

  const updateSystemPlan = (planId: PlanId, updates: Partial<SubscriptionPlan>) => {
    setSystemPlans(prev => ({
      ...prev,
      [planId]: { ...prev[planId], ...updates }
    }));
  };

  const upgradePlan = async (planId: PlanId) => {
    if (!user) return false;
    const plan = systemPlans[planId];
    setStats(prev => ({
      ...prev,
      postsReadTarget: plan.readLimit,
      commentsTarget: plan.commentLimit,
      transactions: [{ id: `sub_${Date.now()}`, amount: plan.price, type: 'subscription_fee', status: 'completed', date: getTodayDate(), description: `Tier Upgrade: ${plan.name}` }, ...prev.transactions]
    }));
    setUser(prev => prev ? { ...prev, planId } : null);
    return true;
  };

  const requestWithdrawal = async (amount: number, method: string) => {
    if (amount > stats.balance) return { success: false, message: 'Insufficient Balance' };
    setStats(prev => ({ ...prev, balance: prev.balance - amount }));
    return { success: true, message: 'Withdrawal processing initiated.' };
  };

  const setLimitModalShown = () => {
    setUser(prev => prev ? { ...prev, lastLimitModalDate: getTodayDate() } : null);
  };

  return (
    <AuthContext.Provider value={{ 
      user, stats, posts, systemPlans, allUsers, 
      login, register, logout, isLoading, addReward, upgradePlan, setLimitModalShown, requestWithdrawal, savePost,
      updatePostStatus, manageUserStatus, updateSystemPlan
    }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) throw new Error('useAuth must be used within AuthProvider');
  return context;
};
